function produccionCarga(){cargarProduccionIA();return `<article class="card"><span class="eyebrow">Producción IA</span><h3>Conectando con AI Production Engine</h3><p class="muted">Inicia el backend en http://127.0.0.1:8000 para ver la línea industrial de producción mock.</p>${estadoProduccionIA.error?`<p class="workflow-error">${estadoProduccionIA.error}</p>`:badge("Cargando","info")}</article>`}
function trabajoActual(){return estadoProduccionIA.seleccionado||estadoProduccionIA.trabajos[0]||{}}
async function accionProduccionIA(accion,id){
  try{
    if(accion==="create"){
      await apiProduccion("/api/production/create",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({topic:"Herramientas de IA para pequeñas empresas",niche:"Tecnología",language:"Español",country:"México",approved_idea:"Explicar por qué una idea necesita auditoría antes de producir",executive_decision:"PRODUCIR",opportunity_score:85})});
    }
    if(accion==="approve" && id) await apiProduccion(`/api/production/${id}/approve`,{method:"POST"});
    if(accion==="reject" && id) await apiProduccion(`/api/production/${id}/reject`,{method:"POST"});
    estadoProduccionIA.cargado=false; await cargarProduccionIA(true); route();
  }catch(e){estadoProduccionIA.error=e.message; route()}
}
function resumenProduccion(){const q=estadoProduccionIA.cola||{};return `<div class="grid four"><article class="metric-card"><small>Total</small><span class="metric-value">${q.total||0}</span></article><article class="metric-card"><small>En producción</small><span class="metric-value">${q.in_production||0}</span></article><article class="metric-card"><small>Aprobados</small><span class="metric-value">${q.approved||0}</span></article><article class="metric-card"><small>Rechazados</small><span class="metric-value">${q.rejected||0}</span></article></div>`}
function colaProduccionIA(){return `${resumenProduccion()}<article class="card"><span class="eyebrow">Cola de Producción</span><h3>De decisión aprobada a video listo para producir</h3><div class="pipeline-flow">${["Auditoría Mundial","Director Ejecutivo IA","Idea aprobada","Guion","Storyboard","Escenas","Assets","Narración","Subtítulos","Música","Efectos","Render","Calidad","Video aprobado"].map((p,i)=>`<div class="flow-step"><span class="flow-index">${String(i+1).padStart(2,"0")}</span><strong>${p}</strong><small>Línea industrial mock</small>${badge(i<13?"Listo":"Pendiente",i<13?"ok":"warn")}</div>`).join("")}</div><button class="primary-btn" data-production-action="create">Crear trabajo mock</button></article>`}
function trabajosProduccionIA(){return `${resumenProduccion()}<article class="card"><span class="eyebrow">Trabajos</span><h3>Producciones activas</h3>${estadoProduccionIA.trabajos.map(j=>`<div class="entity-row"><div><span class="entity-title">${j.topic}</span><span class="entity-meta">${j.country} · ${j.language} · ${j.niche} · Score ${j.opportunity_score}</span></div><div class="quick-actions">${badge(j.status,j.status==="Video aprobado"?"ok":j.status==="Rechazado"?"hot":"info")}<button class="ghost-btn" data-production-action="approve" data-job-id="${j.id}">Aprobar</button><button class="ghost-btn" data-production-action="reject" data-job-id="${j.id}">Rechazar</button></div></div>`).join("")}</article>`}
function storyboardProduccionIA(){const j=trabajoActual();return `<article class="card"><span class="eyebrow">Storyboard</span><h3>${j.approved_idea||"Idea aprobada"}</h3>${(j.storyboard||[]).map((s,i)=>`<div class="timeline-item"><time>${String(i+1).padStart(2,"0")}</time><div><strong>Bloque ${i+1}</strong><p>${s}</p></div></div>`).join("")}</article>`}
function escenasProduccionIA(){const j=trabajoActual();return `<div class="scene-grid">${(j.scenes||[]).map(s=>`<article class="scene-card"><span>${s.id}</span><strong>${s.title}</strong><p>${s.visual_description}</p><small>${s.duration_seconds}s · ${s.camera_direction}</small></article>`).join("")}</div>`}
function assetsProduccionIA(){const j=trabajoActual();return `<article class="card"><span class="eyebrow">Assets</span><h3>Recursos definidos, no generados</h3>${(j.assets||[]).map(a=>`<div class="entity-row"><div><span class="entity-title">${a.asset_type}</span><span class="entity-meta">${a.description}</span></div>${badge(a.status,"ok")}</div>`).join("")}</article>`}
function narracionProduccionIA(){const n=trabajoActual().narration||{};return `<article class="card"><span class="eyebrow">Narración</span><h3>${n.voice||"Voz IA mock"}</h3><p>${n.script||"Narración pendiente."}</p>${[["Tono",n.tone],["Duración",`${n.duration_seconds||0}s`],["Estado",n.status]].map(([a,b])=>`<div class="director-row"><span>${a}</span><strong>${b||"Pendiente"}</strong></div>`).join("")}</article>`}
function subtitulosProduccionIA(){const s=trabajoActual().subtitles||{};return `<article class="card"><span class="eyebrow">Subtítulos</span><h3>${s.language||"Idioma pendiente"}</h3>${(s.lines||[]).map(line=>`<div class="entity-row"><div><span class="entity-title">${line}</span><span class="entity-meta">Línea preparada para futura sincronización.</span></div>${badge(s.status||"Pendiente","info")}</div>`).join("")}</article>`}
