const rutasVideoAnimado = ["animated-engine","scene-composer","animated-timeline","motion-graphics","image-to-video","first-render","animation-templates","animated-storyboard","animation-timeline","animation-assets","animation-characters","animation-backgrounds","animation-effects","animation-preview","animation-render"];
