function timelineAnimado(){const t=estadoAnimacion.timelineAnimado||timelineDemo();const total=Math.max(1,t.total_duration_seconds||40);return `<article class="card animation-studio"><span class="eyebrow">Timeline Animado</span><h3>Vista previa temporal antes de exportar</h3><p>Controla entrada, salida, keyframes, zoom, paneo, subtítulos y transiciones sin renderizar MP4.</p><div class="quick-actions"><button class="primary-btn" data-animation-action="build-timeline">Generar timeline animado</button><button class="ghost-btn" data-go="scene-composer">Ver compositor</button></div>${estadoAnimacion.error?`<p class="workflow-error">${estadoAnimacion.error}</p>`:""}</article><div class="animated-timeline-layout"><article class="card"><span class="eyebrow">Duración total</span><h3>${total}s · ${t.scene_count||t.scenes.length} escenas</h3><div class="time-ruler">${Array.from({length:Math.ceil(total/5)+1},(_,i)=>`<span>${i*5}s</span>`).join("")}</div><div class="timeline-track">${t.scenes.map(s=>`<section style="--start:${(s.start_time/total)*100}%;--width:${((s.end_time-s.start_time)/total)*100}%"><strong>${s.title}</strong><small>${s.start_time}s-${s.end_time}s · ${s.transition.type}</small></section>`).join("")}</div><div class="keyframe-rail">${t.scenes.flatMap(s=>s.keyframes.slice(0,8).map(k=>`<i style="left:${(k.time/total)*100}%" title="${k.layer} · ${k.event}"></i>`)).join("")}</div></article><article class="card timeline-preview-card"><span class="eyebrow">Preview 9:16</span><div class="phone-preview timeline-phone"><div class="scene-bg"></div><div class="scene-glow one"></div><div class="scene-title">${t.scenes[0]?.title||"Timeline"}</div><div class="timeline-playhead"></div><div class="scene-character"><i></i><b></b></div><div class="scene-main-text">${t.scenes[0]?.text_events?.[0]?.description||"Aparecen textos y capas por tiempo."}</div><div class="scene-subtitle">${t.scenes[0]?.subtitles?.[0]?.text||"Subtitulo por segundo."}</div></div></article></div><div class="timeline-detail-grid">${t.scenes.map((s,i)=>`<article class="card timeline-scene-card"><span class="eyebrow">Escena ${String(i+1).padStart(2,"0")} · ${s.start_time}s-${s.end_time}s</span><h3>${s.title}</h3><div class="timeline-tags"><span>${s.entry_animation}</span><span>${s.exit_animation}</span><span>Zoom ${s.zoom.from}→${s.zoom.to}</span><span>Paneo ${s.pan.direction}</span></div><div class="layer-list">${s.layers.map(l=>`<div><strong>${l.name}</strong><small>${l.type} · ${l.animation}</small></div>`).join("")}</div><div class="subtitle-list">${s.subtitles.map(x=>`<p><b>${x.time}s</b> ${x.text}</p>`).join("")}</div></article>`).join("")}</div>`}
