function pantallaRenderEngine(){if(!estadoRender.cargado){cargarRenderEngine();return `<article class="card render-engine-card"><span class="eyebrow">Render Engine</span><h3>Verificando FFmpeg</h3><p class="muted">Consultando /api/render/status.</p>${estadoRender.error?`<p class="workflow-error">${estadoRender.error}</p>`:badge("Cargando","info")}</article>`}const s=estadoRender.status||{};return `<article class="card render-engine-card ${s.available?"available":"missing"}"><span class="eyebrow">Render Engine</span><h3>${s.available?"FFmpeg disponible":"FFmpeg no encontrado"}</h3><p>Esta fase solo verifica integración. No se genera MP4 todavía.</p><div class="grid four"><article class="metric-card"><small>Estado</small><span class="metric-value">${s.installed?"Instalado":"No"}</span></article><article class="metric-card"><small>Disponible</small><span class="metric-value">${s.available?"Sí":"No"}</span></article><article class="metric-card"><small>Versión</small><span class="metric-value render-version">${s.version||"Sin versión"}</span></article><article class="metric-card"><small>Ruta</small><span class="metric-value render-path">${s.path||"Sin ruta"}</span></article></div>${badge(s.available?"Listo para fases futuras":"Requiere instalación",s.available?"ok":"warn")}</article>`}
async function cargarMotionGraphics(forzar=false){if(estadoMotion.cargando||estadoMotion.cargado&&!forzar)return;try{estadoMotion.cargando=true;estadoMotion.error="";const r=await fetch(`${API_BASE}/api/render/motion-graphics`);if(!r.ok)throw new Error(UI.error);estadoMotion.plan=await r.json();estadoMotion.cargado=true}catch(e){estadoMotion.error=e.message}finally{estadoMotion.cargando=false;if(location.hash.replace("#","")==="motion-graphics")route()}}
async function aplicarMotionGraphics(){try{estadoMotion.cargando=true;estadoMotion.error="";route();const r=await fetch(`${API_BASE}/api/render/test-video`,{method:"POST"});if(!r.ok)throw new Error(UI.error);const data=await r.json();if(data.status==="error")throw new Error(data.message||"FFmpeg no pudo generar el video.");estadoMotion.resultado=data;estadoPrimerRender.resultado=data}catch(e){estadoMotion.error=e.message}finally{estadoMotion.cargando=false;route()}}
function pantallaMotionGraphics(){if(!estadoMotion.cargado){cargarMotionGraphics();return `<article class="card motion-card"><span class="eyebrow">Motion Graphics</span><h3>Cargando paquete visual</h3><p class="muted">Consultando animaciones, transiciones, cámara y layouts desde el backend.</p>${estadoMotion.error?`<p class="workflow-error">${estadoMotion.error}</p>`:badge("Cargando","info")}</article>`}const p=estadoMotion.plan||{};const s=p.scenes?.[0]||{};const anim=s.animation||{};const res=estadoMotion.resultado;return `<article class="card motion-card"><span class="eyebrow">Motion Graphics Engine</span><h3>${p.name||"TikTok/Reels Motion Pack"}</h3><p>Paquete visual local para mejorar el primer render con entradas, salidas, cámara, layouts, partículas y transiciones sin usar APIs externas.</p><div class="quick-actions"><button class="primary-btn" data-render-action="motion-graphics" ${estadoMotion.cargando?"disabled":""}>${estadoMotion.cargando?"Aplicando Motion Graphics...":"Aplicar Motion Graphics"}</button><button class="ghost-btn" data-go="first-render">Ver primer render</button></div>${estadoMotion.error?`<p class="workflow-error">${estadoMotion.error}</p>`:""}<div class="motion-grid"><div class="motion-preview"><div class="motion-orb one"></div><div class="motion-orb two"></div><div class="motion-grid-lines"></div><strong>HOOK VISUAL</strong><span>Texto grande con glow y highlight</span><small>${s.transition?.name||"Cross Fade"} · ${s.camera?.name||"Zoom lento"}</small></div><div class="motion-panel"><div class="motion-row"><span>Animación elegida</span><strong>${anim.entrada||"Fade"} + ${anim.texto||"Glow"}</strong></div><div class="motion-row"><span>Transición</span><strong>${s.transition?.name||"Cross Fade"}</strong></div><div class="motion-row"><span>Cámara</span><strong>${s.camera?.name||"Zoom lento"}</strong></div><div class="motion-row"><span>Layout</span><strong>${s.layout?.name||"Título grande"}</strong></div><div class="motion-row"><span>Duración</span><strong>${p.total_duration_seconds||12}s</strong></div></div></div>${res?`<article class="card render-output-card"><span class="eyebrow">Render actualizado</span><h3>output/video_0001.mp4</h3><p>${res.duration_seconds}s · ${formatoBytes(res.size_bytes)} · ${res.resolution}</p>${badge("Motion Graphics aplicado","ok")}</article>`:""}</article><div class="motion-scenes">${(p.scenes||[]).map(x=>`<article class="card"><span class="eyebrow">Escena ${x.scene}</span><h3>${x.layout.name}</h3><p>${x.animation.entrada} · ${x.animation.texto} · ${x.transition.name}</p>${badge(x.camera.name,"info")}</article>`).join("")}</div>`}
function archivoADataURL(file){return new Promise((resolve,reject)=>{const r=new FileReader();r.onload=()=>resolve(r.result);r.onerror=reject;r.readAsDataURL(file)})}
async function subirImagenVideo(file){if(!file)return;try{estadoImagenVideo.cargando=true;estadoImagenVideo.error="";route();const dataUrl=await archivoADataURL(file);estadoImagenVideo.preview=dataUrl;const r=await fetch(`${API_BASE}/api/image-video/upload`,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({filename:file.name,data_url:dataUrl})});if(!r.ok)throw new Error(UI.error);estadoImagenVideo.upload=await r.json()}catch(e){estadoImagenVideo.error=e.message}finally{estadoImagenVideo.cargando=false;route()}}
async function crearVideoDesdeImagen(){try{estadoImagenVideo.cargando=true;estadoImagenVideo.error="";route();const v=id=>document.getElementById(id)?.value||"";const r=await fetch(`${API_BASE}/api/image-video/create`,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({upload_id:estadoImagenVideo.upload?.upload_id,title:v("imageVideoTitle"),subtitle:v("imageVideoSubtitle"),style:v("imageVideoStyle")})});if(!r.ok)throw new Error(UI.error);const data=await r.json();if(data.status==="error"||data.render?.status==="error")throw new Error(data.render?.message||data.message||"No se pudo generar el video.");estadoImagenVideo.job=data}catch(e){estadoImagenVideo.error=e.message}finally{estadoImagenVideo.cargando=false;route()}}
function pantallaImagenVideo(){const upload=estadoImagenVideo.upload;const a=upload?.analysis||{};const job=estadoImagenVideo.job;const render=job?.render;return `<article class="card image-video-card"><span class="eyebrow">Imagen a Video</span><h3>Convierte una imagen en un video vertical animado</h3><p>Sube una imagen y el sistema la adapta a 9:16 con fondo animado, zoom/paneo, texto superior, subtítulo inferior y render MP4 local.</p><div class="image-video-layout"><div class="image-video-preview">${estadoImagenVideo.preview?`<img src="${estadoImagenVideo.preview}" alt="Preview de imagen" />`:`<span>Sube una imagen</span>`}</div><div class="image-video-form"><label class="upload-field"><span>Imagen</span><input type="file" accept="image/png,image/jpeg,image/webp,image/gif" id="imageVideoFile" /></label><div class="field"><label>Título</label><input id="imageVideoTitle" value="${job?.title||"Una imagen puede contar una historia"}" /></div><div class="field"><label>Subtítulo</label><input id="imageVideoSubtitle" value="${job?.subtitle||"Video vertical generado localmente."}" /></div><div class="field"><label>Estilo</label><select id="imageVideoStyle">${["Curiosidad","Misterio","Educativo","Negocio","Historia"].map(x=>`<option ${job?.style===x?"selected":""}>${x}</option>`).join("")}</select></div><button class="primary-btn" data-image-video-action="create" ${estadoImagenVideo.cargando||!upload?"disabled":""}>${estadoImagenVideo.cargando?"Generando video...":"Generar video desde imagen"}</button>${estadoImagenVideo.error?`<p class="workflow-error">${estadoImagenVideo.error}</p>`:""}</div></div></article>${upload?`<div class="grid four"><article class="metric-card"><small>Ancho</small><span class="metric-value">${a.width||0}</span></article><article class="metric-card"><small>Alto</small><span class="metric-value">${a.height||0}</span></article><article class="metric-card"><small>Formato</small><span class="metric-value">${a.format||"-"}</span></article><article class="metric-card"><small>Orientación</small><span class="metric-value">${a.orientation||"-"}</span></article></div>`:""}${job?`<article class="card render-output-card"><span class="eyebrow">Render generado</span><h3>output/image_video_0001.mp4</h3><p class="render-path">${render.path}</p><div class="grid four"><article class="metric-card"><small>Estado</small><span class="metric-value">${render.status}</span></article><article class="metric-card"><small>Duración</small><span class="metric-value">${render.duration_seconds}s</span></article><article class="metric-card"><small>Tamaño</small><span class="metric-value">${formatoBytes(render.size_bytes)}</span></article><article class="metric-card"><small>Resolución</small><span class="metric-value">${render.resolution}</span></article></div>${badge("Imagen a video OK","ok")}</article>`:""}${job?.motion_plan?`<div class="motion-scenes">${["background","framing","camera","text"].map(k=>`<article class="card"><span class="eyebrow">${k}</span><h3>${Array.isArray(job.motion_plan[k])?job.motion_plan[k].join(" · "):job.motion_plan[k]}</h3></article>`).join("")}</div>`:""}`}
const estadoNarracion = { cargando:false, error:"", script:"La inteligencia artificial no debe crear videos sin pensar. Primero analiza una oportunidad. Luego prepara escenas, voz, subtitulos y ritmo. Finalmente deja todo listo para producir un video animado claro.", plan:null, job:null };
function leerGuionNarracion(){estadoNarracion.script=document.getElementById("narrationScript")?.value||estadoNarracion.script}
async function accionNarracion(action){try{leerGuionNarracion();estadoNarracion.cargando=true;estadoNarracion.error="";route();const endpoint=action==="generate"?"generate":action==="script"?"script":"plan";const r=await fetch(`${API_BASE}/api/narration/${endpoint}`,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({script:estadoNarracion.script,voice:"Narrador Local Mock"})});if(!r.ok)throw new Error(UI.error);const data=await r.json();if(action==="generate"){estadoNarracion.job=data;estadoNarracion.plan=data}else{estadoNarracion.plan=data}}catch(e){estadoNarracion.error=e.message}finally{estadoNarracion.cargando=false;route()}}
function narracionGuionCard(){return `<article class="card narration-card"><span class="eyebrow">Narration Engine</span><h3>Guion para narración local MOCK</h3><p>Esta fase no genera voz real. Prepara segmentación, tiempos, subtítulos y un archivo temporal para conectar TTS en el futuro.</p><textarea id="narrationScript" class="narration-script">${estadoNarracion.script}</textarea><div class="quick-actions"><button class="primary-btn" data-narration-action="plan">${estadoNarracion.cargando?"Planificando...":"Planificar narración"}</button><button class="ghost-btn" data-narration-action="script">Solo segmentar</button><button class="ghost-btn" data-narration-action="generate">Generar MOCK</button></div>${estadoNarracion.error?`<p class="workflow-error">${estadoNarracion.error}</p>`:""}</article>`}
function pantallaNarracion(id){const p=estadoNarracion.plan;const seg=p?.timing?.segments||p?.segments||[];const voice=p?.voice_plan||{};const subs=p?.subtitles||[];const tracks=p?.speech_timeline||[];if(id==="narration-script")return narracionGuionCard();if(!p)return `${narracionGuionCard()}<article class="card narration-card"><h3>Sin plan todavía</h3><p class="muted">Presiona Planificar narración para ver segmentación, voz, subtítulos y timeline.</p>${badge("Esperando guion","info")}</article>`;if(id==="narration-segmentation")return `${narracionGuionCard()}${tabla(["Escena","Texto","Duración","Palabras","Velocidad"],seg.map(s=>[s.scene,s.text,`${s.duration_seconds||s.duration}s`,s.words,s.speed||s.words_per_second]))}`;if(id==="narration-voice-plan")return `${narracionGuionCard()}<div class="grid four"><article class="metric-card"><small>Voz</small><span class="metric-value">${voice.voice}</span></article><article class="metric-card"><small>Tono</small><span class="metric-value">${voice.tone}</span></article><article class="metric-card"><small>Energía</small><span class="metric-value">${voice.energy}</span></article><article class="metric-card"><small>Velocidad</small><span class="metric-value">${voice.speed}</span></article></div><div class="grid two"><article class="card"><span class="eyebrow">Pausas</span>${(voice.pauses||[]).map(x=>`<p>Escena ${x.after_scene}: ${x.duration_seconds}s</p>`).join("")}</article><article class="card"><span class="eyebrow">Énfasis</span>${(voice.emphasis||[]).map(x=>`<p><strong>${x.word}</strong> · ${x.style}</p>`).join("")}</article></div>`;if(id==="narration-subtitles")return `<div class="narration-subtitle-grid">${subs.map(s=>`<article class="card narration-card"><span class="eyebrow">Escena ${s.scene} · ${s.start}s-${s.end}s</span><h3>${s.lines.join("<br>")}</h3><p>${s.position} · máximo ${s.max_chars_per_line} caracteres por línea</p></article>`).join("")}</div>`;if(id==="narration-timeline")return `<article class="card narration-card"><span class="eyebrow">Timeline de Voz</span><h3>${p.timing.total_duration_seconds}s planificados</h3><div class="voice-timeline">${tracks.map(t=>`<section style="--w:${Math.max(12,t.duration*8)}%"><strong>Escena ${t.scene}</strong><small>${t.start}s-${t.end}s · ${t.status}</small></section>`).join("")}</div></article>`;return `${narracionGuionCard()}${estadoNarracion.job?`<article class="card render-output-card"><span class="eyebrow">Narración MOCK generada</span><h3>${estadoNarracion.job.job_id}</h3><p class="render-path">${estadoNarracion.job.audio.path}</p>${badge("Archivo temporal creado","ok")}</article>`:`<article class="card narration-card"><h3>Preview de narración</h3><p>Genera el MOCK para crear el archivo temporal de narración local.</p>${badge("Sin TTS real","warn")}</article>`}`}
async function cargarPersonajes(forzar=false){if(estadoPersonajes.cargando||estadoPersonajes.cargado&&!forzar)return;try{estadoPersonajes.cargando=true;estadoPersonajes.error="";const r=await fetch(`${API_BASE}/api/characters/library`);if(!r.ok)throw new Error(UI.error);estadoPersonajes.library=await r.json();estadoPersonajes.cargado=true}catch(e){estadoPersonajes.error=e.message}finally{estadoPersonajes.cargando=false;if(location.hash.replace("#","").startsWith("characters-"))route()}}
function sincronizarControlesPersonaje(){estadoPersonajes.seleccionado=document.getElementById("characterSelect")?.value||estadoPersonajes.seleccionado;estadoPersonajes.expresion=document.getElementById("characterExpression")?.value||estadoPersonajes.expresion;estadoPersonajes.pose=document.getElementById("characterPose")?.value||estadoPersonajes.pose;estadoPersonajes.animacion=document.getElementById("characterAnimation")?.value||estadoPersonajes.animacion}
async function previsualizarPersonaje(){try{estadoPersonajes.cargando=true;estadoPersonajes.error="";route();const r=await fetch(`${API_BASE}/api/characters/animate`,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({character_id:estadoPersonajes.seleccionado,expression:estadoPersonajes.expresion,pose:estadoPersonajes.pose,animation:estadoPersonajes.animacion,text:"La IA explica tecnologia, negocio e historia con un personaje."})});if(!r.ok)throw new Error(UI.error);estadoPersonajes.preview=await r.json()}catch(e){estadoPersonajes.error=e.message}finally{estadoPersonajes.cargando=false;route()}}
function personajeFigura(ch){return `<div class="character-stage"><div class="character-grid-lines"></div><div class="character-avatar" style="--char:${ch?.color_principal?.replace("0x","#")||"#38bdf8"}"><i></i><b></b><em></em><span></span></div><strong>${ch?.nombre||"Narrador Hombre"}</strong><small>${estadoPersonajes.expresion} · ${estadoPersonajes.pose} · ${estadoPersonajes.animacion}</small></div>`}
function pantallaPersonajes(id){if(!estadoPersonajes.cargado){cargarPersonajes();return `<article class="card character-card"><span class="eyebrow">Personajes</span><h3>Cargando biblioteca de personajes</h3>${estadoPersonajes.error?`<p class="workflow-error">${estadoPersonajes.error}</p>`:badge("Cargando","info")}</article>`}const lib=estadoPersonajes.library||{};const chars=lib.characters||[];const ch=chars.find(x=>x.id===estadoPersonajes.seleccionado)||chars[0]||{};const selector=`<article class="card character-card"><span class="eyebrow">Editor de personaje</span><h3>Selecciona personaje, expresión, pose y animación</h3><div class="form-grid"><div class="field"><label>Personaje</label><select id="characterSelect">${chars.map(x=>`<option value="${x.id}" ${x.id===estadoPersonajes.seleccionado?"selected":""}>${x.nombre}</option>`).join("")}</select></div><div class="field"><label>Expresión</label><select id="characterExpression">${(lib.expressions||[]).map(x=>`<option ${x===estadoPersonajes.expresion?"selected":""}>${x}</option>`).join("")}</select></div><div class="field"><label>Pose</label><select id="characterPose">${(lib.poses||[]).map(x=>`<option ${x===estadoPersonajes.pose?"selected":""}>${x}</option>`).join("")}</select></div><div class="field"><label>Animación</label><select id="characterAnimation">${(lib.animations||[]).map(x=>`<option ${x===estadoPersonajes.animacion?"selected":""}>${x}</option>`).join("")}</select></div></div><div class="quick-actions"><button class="primary-btn" data-character-action="preview">${estadoPersonajes.cargando?"Generando preview...":"Ver preview"}</button><button class="ghost-btn" data-go="scene-composer">Ver compositor</button></div>${estadoPersonajes.error?`<p class="workflow-error">${estadoPersonajes.error}</p>`:""}</article>`;const preview=`<article class="card character-preview-card"><span class="eyebrow">Preview 9:16</span>${personajeFigura(ch)}${estadoPersonajes.preview?`<div class="layer-list"><div><strong>Gesto</strong><small>${estadoPersonajes.preview.gesture.gesture} · ${estadoPersonajes.preview.gesture.reason}</small></div><div><strong>Lip sync</strong><small>${estadoPersonajes.preview.lip_sync.inicio}s-${estadoPersonajes.preview.lip_sync.fin}s · sin voz real todavía</small></div></div>`:""}</article>`;if(id==="characters-library")return `<div class="character-library-grid">${chars.map(x=>`<article class="card character-tile" style="--char:${x.color_principal.replace("0x","#")}"><div class="mini-character" style="--char:${x.color_principal.replace("0x","#")}"></div><h3>${x.nombre}</h3><p>${x.categoria} · ${x.estilo}</p>${badge(x.animaciones_soportadas.length+" animaciones","info")}</article>`).join("")}</div>`;if(id==="characters-animations")return tabla(["Animación","Uso"],(lib.animations||[]).map(x=>[x,"Personaje local"]));if(id==="characters-expressions")return tabla(["Expresión","Estado"],(lib.expressions||[]).map(x=>[x,badge("Disponible","ok")]));if(id==="characters-poses")return tabla(["Pose","Estado"],(lib.poses||[]).map(x=>[x,badge("Disponible","ok")]));return `<div class="character-editor-grid">${selector}${preview}</div>`}
async function generarPrimerRender(){try{estadoPrimerRender.cargando=true;estadoPrimerRender.error="";route();const r=await fetch(`${API_BASE}/api/render/test-video`,{method:"POST"});if(!r.ok)throw new Error(UI.error);const data=await r.json();if(data.status==="error")throw new Error(data.message||"FFmpeg no pudo generar el video.");estadoPrimerRender.resultado=data}catch(e){estadoPrimerRender.error=e.message}finally{estadoPrimerRender.cargando=false;route()}}
function formatoBytes(bytes){const n=Number(bytes||0);if(!n)return"0 KB";if(n<1024*1024)return`${Math.round(n/1024)} KB`;return`${(n/(1024*1024)).toFixed(2)} MB`}
function pantallaPrimerRender(){const r=estadoPrimerRender.resultado;const fileLink=r?.path?`file:///${String(r.path).replaceAll("\\","/")}`:"";return `<article class="card first-render-card"><span class="eyebrow">Primer Render MP4</span><h3>Generar un video animado real de prueba</h3><p>Usa 4 escenas verticales 9:16, textos grandes, subtítulos simples, fondos animados y transiciones básicas. Sin voz, sin música, sin IA real y sin APIs externas.</p><div class="quick-actions"><button class="primary-btn" data-render-action="test-video" ${estadoPrimerRender.cargando?"disabled":""}>${estadoPrimerRender.cargando?"Generando MP4...":"Generar primer MP4"}</button>${fileLink?`<a class="ghost-btn" href="${fileLink}" target="_blank" rel="noreferrer">Abrir / ver video</a>`:""}</div>${estadoPrimerRender.error?`<p class="workflow-error">${estadoPrimerRender.error}</p>`:""}${r?`<div class="grid four render-result-grid"><article class="metric-card"><small>Estado</small><span class="metric-value">${r.status==="rendered"?"Generado":"Pendiente"}</span></article><article class="metric-card"><small>Duración</small><span class="metric-value">${r.duration_seconds}s</span></article><article class="metric-card"><small>Tamaño</small><span class="metric-value">${formatoBytes(r.size_bytes)}</span></article><article class="metric-card"><small>Escenas</small><span class="metric-value">${r.scene_count}</span></article></div><article class="card render-output-card"><span class="eyebrow">Archivo generado</span><h3>output/video_0001.mp4</h3><p class="render-path">${r.path}</p>${badge("FFmpeg OK","ok")}</article>`:`<article class="card render-output-card"><span class="eyebrow">Resultado</span><h3>output/video_0001.mp4</h3><p class="muted">Presiona el botón para generar el primer video MP4 real.</p>${badge("Listo para render","info")}</article>`}</article>`}

const estadoProyectos = { cargado:false, cargando:false, error:"", lista:[], activo:null, detalle:null, soportados:null };
const rutasProyecto = ["projects","create-project","project-library","project-documents","active-project","project-sources","content-brain","director-ai","ai-timeline"];
async function apiProyecto(ruta, opciones={}){const r=await fetch(`${API_BASE}${ruta}`,opciones);if(!r.ok)throw new Error(UI.error);if(r.status===204)return null;return r.json()}
async function cargarProyectos(forzar=false){
  if(estadoProyectos.cargando || (estadoProyectos.cargado && !forzar)) return;
  try{
    estadoProyectos.cargando=true;
    const [lista, activo, soportados] = await Promise.all([apiProyecto("/api/projects"), apiProyecto("/api/projects/active"), apiProyecto("/api/projects/supported-sources")]);
    estadoProyectos.lista=lista; estadoProyectos.activo=activo; estadoProyectos.soportados=soportados;
    const base = activo.active_project || lista[0];
    estadoProyectos.detalle = base ? await apiProyecto(`/api/projects/${base.id}`) : null;
    estadoProyectos.cargado=true; estadoProyectos.error="";
  }catch(e){estadoProyectos.error=e.message}
  finally{estadoProyectos.cargando=false;if(rutasProyecto.includes(location.hash.replace("#",""))) route()}
}
function proyectoCarga(){cargarProyectos();return `<article class="card"><span class="eyebrow">Proyectos</span><h3>Conectando biblioteca de fuentes</h3><p class="muted">Inicia el backend en http://127.0.0.1:8000 para usar proyectos opcionales.</p>${estadoProyectos.error?`<p class="workflow-error">${estadoProyectos.error}</p>`:badge("Cargando","info")}</article>`}
function modoProyectoCard(){if(!estadoProyectos.cargado)cargarProyectos();const activo=estadoProyectos.activo;const global=!activo?.active_project;return `<article class="card source-mode-card ${global?"global":"linked"}"><span class="eyebrow">Modo de trabajo IA</span><h3>${global?"Contenido global":"Proyecto vinculado"}</h3><p>${global?"La IA trabaja sin proyecto y analiza oportunidades globales/locales simuladas.":`Actualmente trabajando con: ${activo.active_project.name}. Solo se usarán fuentes autorizadas.`}</p><div class="quick-actions"><button class="ghost-btn" data-project-action="deactivate">Modo global</button><button class="primary-btn" data-go="active-project">Ver proyecto activo</button></div></article>`}
function listaProyectos(){if(!estadoProyectos.cargado)return proyectoCarga();return `${modoProyectoCard()}<div class="project-grid">${estadoProyectos.lista.map(p=>`<article class="card project-card"><span class="eyebrow">${p.project_type}</span><h3>${p.name}</h3><p>${p.description}</p><div class="style-meta"><span>${p.primary_language}</span><span>${p.country}</span><span>${p.status}</span></div><div class="quick-actions"><button class="primary-btn" data-project-action="activate" data-project-id="${p.id}">Activar</button><button class="ghost-btn" data-project-action="open" data-project-id="${p.id}">Ver documentos</button></div></article>`).join("")}</div>`}
function crearProyecto(){return `${modoProyectoCard()}<article class="card"><span class="eyebrow">Crear Proyecto</span><h3>Nuevo proyecto opcional</h3><p class="muted">La plataforma funciona perfecto sin proyectos. Activa uno solo cuando quieras usar información autorizada.</p><div class="form-grid"><div class="field"><label>Nombre</label><input id="projectName" value="Proyecto Cliente ABC" /></div><div class="field"><label>Idioma principal</label><input id="projectLanguage" value="Español" /></div><div class="field"><label>País</label><input id="projectCountry" value="Chile" /></div><div class="field"><label>Tipo de proyecto</label><select id="projectType">${["Empresa","Marca","Libro","Novela","Serie","Curso","Producto","Cliente","Canal","Otro"].map(x=>`<option>${x}</option>`).join("")}</select></div><div class="field workflow-span"><label>Descripción</label><input id="projectDescription" value="Biblioteca autorizada para crear contenido de marca con contexto propio." /></div></div><button class="primary-btn" data-project-action="create">Crear proyecto</button></article>`}
function bibliotecaProyecto(){if(!estadoProyectos.cargado)return proyectoCarga();const detalle=estadoProyectos.detalle;return `${modoProyectoCard()}<article class="card"><span class="eyebrow">Biblioteca</span><h3>Arrastra archivos para registrarlos</h3><p class="muted">PDF, DOCX, TXT, Markdown, CSV, JSON, HTML, PNG, JPG, WEBP, MP4 y MP3. No se procesan todavía.</p><div class="dropzone" id="projectDropzone"><strong>Arrastra archivos aquí</strong><span>o haz clic para simular documentos ficticios</span></div></article>${documentosProyecto(detalle)}`}
function documentosProyecto(detalle=estadoProyectos.detalle){if(!estadoProyectos.cargado)return proyectoCarga();if(!detalle&&estadoProyectos.lista[0]){apiProyecto(`/api/projects/${estadoProyectos.lista[0].id}`).then(d=>{estadoProyectos.detalle=d;route()});return `${modoProyectoCard()}<article class="card"><h3>Cargando documentos</h3><p class="muted">Preparando biblioteca del proyecto.</p></article>`}if(!detalle)return `${modoProyectoCard()}<article class="card"><h3>Sin proyecto</h3><p class="muted">Crea un proyecto para registrar documentos opcionales.</p></article>`;return `<article class="card"><span class="eyebrow">Documentos</span><h3>${detalle.project.name}</h3>${detalle.documents.length?tabla(["Nombre","Tipo","Peso","Estado","Fecha"],detalle.documents.map(d=>[d.source_file.filename,d.source_file.file_type,`${Math.max(1,Math.round(d.source_file.size_bytes/1024))} KB`,badge(d.source_file.status,d.authorized_for_ai?"ok":"warn"),new Date(d.source_file.uploaded_at).toLocaleDateString("es-CL")])):`<p class="muted">Aún no hay documentos registrados.</p>`}<div class="quick-actions"><button class="primary-btn" data-project-action="fake-docs">Subir documentos ficticios</button><button class="ghost-btn" data-go="project-library">Ir a biblioteca</button></div></article>`}
function proyectoActivo(){if(!estadoProyectos.cargado)return proyectoCarga();const activo=estadoProyectos.activo;return `${modoProyectoCard()}<article class="card active-project-card"><span class="eyebrow">Proyecto Activo</span><h3>Actualmente trabajando con:</h3><div class="active-choice"><span class="choice-dot ${activo.active_project?"":"selected"}"></span><strong>Ningún proyecto</strong><small>Modo global</small></div>${activo.active_project?`<div class="active-choice selected"><span class="choice-dot selected"></span><strong>${activo.active_project.name}</strong><small>${activo.active_project.project_type} · ${activo.active_project.country} · ${activo.active_project.primary_language}</small></div>`:""}<p class="muted">${activo.message}</p><div class="quick-actions"><button class="ghost-btn" data-project-action="deactivate">Volver al modo global</button><button class="primary-btn" data-go="projects">Elegir proyecto</button></div></article>`}
function fuentesProyecto(){if(!estadoProyectos.cargado)return proyectoCarga();const detalle=estadoProyectos.detalle;return `${modoProyectoCard()}<article class="card"><span class="eyebrow">Fuentes soportadas</span><h3>Arquitectura preparada</h3><div class="source-chip-grid">${estadoProyectos.soportados.supported_document_types.map(x=>`<span>${x}</span>`).join("")}</div><p class="muted">${estadoProyectos.soportados.note}</p></article>${detalle?tabla(["Fuente","Tipo","Alcance"],detalle.sources.map(s=>[s.name,s.source_type,s.authorized_scope])):""}`}
async function accionProyecto(accion,id){try{if(accion==="create"){const payload={name:document.getElementById("projectName").value,description:document.getElementById("projectDescription").value,primary_language:document.getElementById("projectLanguage").value,country:document.getElementById("projectCountry").value,project_type:document.getElementById("projectType").value};await apiProyecto("/api/projects",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(payload)});location.hash="projects"}if(accion==="activate"){await apiProyecto(`/api/projects/${id}/activate`,{method:"POST"})}if(accion==="deactivate"){await apiProyecto("/api/projects/deactivate",{method:"POST"})}if(accion==="open"){const detail=await apiProyecto(`/api/projects/${id}`);estadoProyectos.detalle=detail;location.hash="project-documents";return}if(accion==="fake-docs"){const project=(estadoProyectos.activo?.active_project||estadoProyectos.lista[0]);if(project){for(const doc of [{filename:"brief-marca.pdf",file_type:"PDF",size_bytes:245000},{filename:"guia-tono.md",file_type:"Markdown",size_bytes:32000},{filename:"datos-campana.csv",file_type:"CSV",size_bytes:88000}]){await apiProyecto(`/api/projects/${project.id}/documents`,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(doc)})}}}estadoProyectos.cargado=false;estadoAgentes.cargado=false;await cargarProyectos(true);renderScreen(location.hash.replace("#","")||"projects")}catch(e){estadoProyectos.error=e.message;renderScreen(location.hash.replace("#","")||"projects")}}
function pantallaProyectos(id){return {"projects":listaProyectos,"create-project":crearProyecto,"project-library":bibliotecaProyecto,"project-documents":()=>documentosProyecto(),"active-project":proyectoActivo,"project-sources":fuentesProyecto}[id]()}
const estadoFlujo = { estado:"sin iniciar", error:"", workflowId:"", canal:null, oportunidad:null, decisionEjecutiva:null, ideas:[], ideaElegida:null, hooks:[], hookElegido:null, historia:null, plan:null, listo:null, progreso:{} };
function badge(t,c=""){return `<span class="badge ${c}">${t}</span>`}
function titulo(id){return (pantallas.find(p=>p.id===id)||{label:"Panel principal"}).label}
function ayuda(id){return `<article class="card module-help"><span class="eyebrow">Ayuda rápida</span><h3>${titulo(id)}</h3><p>${ayudas[id]||"Esta sección te ayuda a tomar mejores decisiones."}</p></article>`}
function tabla(cols,rows){return `<article class="table-card"><table class="table"><thead><tr>${cols.map(c=>`<th>${c}</th>`).join("")}</tr></thead><tbody>${rows.map(r=>`<tr>${r.map(x=>`<td>${x}</td>`).join("")}</tr>`).join("")}</tbody></table></article>`}
function metricas(){return `<div class="grid metrics">${datos.metricas.map(([a,b,c])=>`<article class="card metric-card"><small>${a}</small><span class="metric-value">${b}</span><span class="delta">${c}</span></article>`).join("")}</div>`}
function mundo(){return `<article class="card world-panel"><span class="eyebrow">Mapa de señales</span><h3>Oportunidades por país, idioma y nicho</h3><p class="muted">Vista simulada para entender dónde conviene crear contenido.</p><div class="world-map"><i class="arc" style="left:18%;top:40%;width:220px;transform:rotate(-10deg)"></i><i class="arc" style="left:34%;top:56%;width:260px;transform:rotate(-20deg)"></i><span class="signal" style="left:18%;top:38%"></span><span class="signal green" style="left:31%;top:61%"></span><span class="signal amber" style="left:55%;top:34%"></span><span class="signal green" style="left:72%;top:53%"></span><span class="world-label">MUNDO</span></div></article>`}
function estado(){return `<article class="card"><span class="eyebrow">Estado</span><h3>Operación clara y segura</h3>${[["Backend","Conectado en modo local","OK"],["IA real","Pendiente para fases futuras","Planificado"],["Publicación","Sin envíos reales","Seguro"],["Contenido","Demostración responsable","Activo"]].map(([a,b,c])=>`<div class="status-row"><div><span class="status-name">${a}</span><span class="status-meta">${b}</span></div>${badge(c,c==="OK"||c==="Activo"?"ok":"info")}</div>`).join("")}</article>`}
function inicio(){return `<section class="welcome-panel"><span class="eyebrow">AppFactoryChile</span><h2>Bienvenido a APP FACTORY VIDEO IA</h2><p>¿Qué deseas hacer hoy?</p><div class="quick-actions"><button class="primary-btn" data-go="channels">Crear un canal</button><button class="primary-btn" data-go="mvp-workflow">Crear contenido</button><button class="ghost-btn" data-go="projects">Continuar proyecto</button><button class="ghost-btn" data-go="videos">Biblioteca</button></div></section>${metricas()}<div class="grid two">${mundo()}${estado()}</div>`}
function radar(){return `<article class="card radar-card"><span class="eyebrow">Radar</span><h3>Temas con mayor oportunidad</h3><div class="radar"><span class="ring r1"></span><span class="ring r2"></span><span class="ring r3"></span><span class="sweep"></span><i class="radar-dot d0"><b>MX</b></i><i class="radar-dot d1"><b>BR</b></i><i class="radar-dot d2"><b>CL</b></i><i class="radar-dot d3"><b>ES</b></i></div></article>`}
function ideas(){return `<article class="card"><span class="eyebrow">Laboratorio de Ideas</span><h3>Ideas antes de producir</h3>${datos.ideas.map(([a,b,c,d])=>`<div class="entity-row"><div><span class="entity-title">${a}</span><span class="entity-meta">Emoción: ${c}. Potencial: ${d}.</span></div>${badge(`${b}/100`,"ok")}</div>`).join("")}</article>`}
function hooks(){return `<article class="card"><span class="eyebrow">Constructor de Hooks</span><h3>Compara inicios posibles</h3><div class="hook-stack">${datos.hooks.map(([a,b])=>`<div class="hook-card"><strong>${a}</strong><span>${b}</span></div>`).join("")}</div></article>`}
function historia(){return `<article class="card director-panel"><span class="eyebrow">Director de Historias</span><h3>Estrategia narrativa recomendada</h3>${[["Objetivo","Explicar una oportunidad de forma simple y útil."],["Narrador","Voz natural, cercana y experta."],["Personaje","Persona realista enfrentando un problema concreto."],["Escenario","Ambiente visual limpio y reconocible."],["Tono","Claro, curioso y responsable."],["Duración","38 segundos."],["Estilo","Oscuro premium con subtítulos dinámicos."]].map(([a,b])=>`<div class="director-row"><span>${a}</span><strong>${b}</strong></div>`).join("")}</article>`}
function plan(){return `<article class="card"><span class="eyebrow">Plan de Producción</span><h3>Cómo debería verse el video</h3>${[["Narrador","Natural y confiable"],["Tipo de voz","Cálida, clara y segura"],["Formato","Vertical 9:16"],["Plataformas","Shorts, Reels y TikTok"],["Música","Moderna, suave y sin derechos"],["Iluminación","Contraste premium"],["Cámara","Movimientos lentos y cortes limpios"],["Color","Base oscura con acentos cian"],["Ritmo","Inicio rápido, explicación clara y cierre breve"]].map(([a,b])=>`<div class="director-row"><span>${a}</span><strong>${b}</strong></div>`).join("")}</article>`}
function aprendizaje(){return `<div class="grid four">${[["Hooks probados","1.284"],["Ideas analizadas","8.420"],["Países aprendiendo","38"],["Mejoras detectadas","126"]].map(([a,b])=>`<article class="card metric-card"><small>${a}</small><span class="metric-value">${b}</span><span class="delta">Aprendizaje acumulado</span></article>`).join("")}</div><article class="card"><h3>Recomendaciones aprendidas</h3>${["Las introducciones cortas retienen mejor.","Los ejemplos locales aumentan comentarios.","La utilidad clara supera al volumen de publicaciones.","La narración cálida funciona mejor para contenido educativo."].map(t=>`<div class="entity-row"><div><span class="entity-title">${t}</span><span class="entity-meta">Principio general, no copia de contenido.</span></div>${badge("Aprendido","ok")}</div>`).join("")}</article>`}
function flujoContenido(){const pasos=["Oportunidad","Investigación","Ideas","Ranking","Hook","Historia","Guion gráfico","Plan","Listo"];return `<article class="card"><span class="eyebrow">Flujo de Contenido</span><h3>De la oportunidad al contenido listo</h3><div class="pipeline-flow">${pasos.map((p,i)=>`<div class="flow-step"><span class="flow-index">${String(i+1).padStart(2,"0")}</span><strong>${p}</strong><small>Responsable: IA editorial</small>${badge("Preparado","ok")}</div>`).join("")}</div></article>`}
function proceso(){return `<article class="card"><span class="eyebrow">Proceso del Video</span><h3>Recorrido completo</h3><div class="decision-timeline">${["Idea","Investigación","Guion","Guion gráfico","Narración","Subtítulos","Render","Programación","Analítica","Aprendizaje"].map((p,i)=>`<div class="timeline-item"><time>${String(i+1).padStart(2,"0")}</time><div><strong>${p}</strong><p>Etapa preparada para fases futuras.</p></div></div>`).join("")}</div></article>`}
function produccion(){return `<article class="card"><span class="eyebrow">Producción en Tiempo Real</span><h3>Cola simulada</h3>${["Idea en revisión","Hook seleccionado","Guion gráfico preparado","Plan de producción listo"].map((p,i)=>`<div class="queue-row"><div><span class="entity-title">Contenido ${String(i+1).padStart(3,"0")}</span><span class="entity-meta">${p}</span><div class="progress-track"><div class="progress-fill" style="width:${45+i*15}%"></div></div></div>${badge("Demostración","info")}</div>`).join("")}</article>`}
function pantalla(id){if(["projects","create-project","project-library","project-documents","active-project","project-sources"].includes(id))return `${ayuda(id)}${pantallaProyectos(id)}`;if(id.startsWith("narration-"))return `${ayuda(id)}${pantallaNarracion(id)}`;if(id.startsWith("characters-"))return `${ayuda(id)}${pantallaPersonajes(id)}`;if(rutasVideoAnimado.includes(id))return `${ayuda(id)}${pantallaVideoAnimado(id)}`;if(id==="render-engine")return `${ayuda(id)}${pantallaRenderEngine()}`;if(rutasProveedoresIA.includes(id))return `${ayuda(id)}${pantallaProveedorIA(id)}`;if(rutasProduccionIA.includes(id))return `${ayuda(id)}${pantallaProduccionIA(id)}`;if(rutasEjecutivas.includes(id))return `${ayuda(id)}${pantallaEjecutiva(id)}`;if(["director-ai","agents","agents-status","ai-timeline","agent-specialties","agent-performance"].includes(id))return `${ayuda(id)}${pantallaAgentes(id)}`;const contenido={"global-intelligence":`${mundo()}${tabla(["País","Tema","Idioma","Competencia","Demanda","Horario","Nivel"],datos.oportunidades)}`,"opportunity-radar":`${radar()}${tabla(["País","Nicho","Idioma","Competencia","Potencial","Hora","Nivel"],datos.oportunidades)}`,"learning-engine":aprendizaje(),"story-director":historia(),"idea-lab":ideas(),"hook-builder":hooks(),"content-brain":`${modoProyectoCard()}<div class="grid two"><article class="card"><span class="eyebrow">Cerebro de Contenido</span><h3>Antes de crear, consulta al Director Ejecutivo IA</h3><p>Solo si la auditoría recomienda producir, el sistema continúa hacia Provider Manager, OpenAI, ideas, hooks y guion.</p>${badge("Provider Manager","info")}</article>${ideas()}</div>`,"content-pipeline":flujoContenido(),"production-plan":plan(),"full-video-journey":proceso(),calendar:tabla(["Zona","País","Idioma","Hora ideal","Pendientes"],[["América","México","Español","13:00","12"],["Europa","España","Español","21:00","8"],["Brasil","Brasil","Portugués","08:00","10"]]),monetization:metricas(),"video-factory-live":produccion(),"digital-factory":`<div class="grid two">${produccion()}${flujoContenido()}</div>`,channels:tabla(["Canal","País","Idioma","Nicho","Estado"],datos.canales.map(r=>[r[0],r[1],r[2],r[3],badge(r[4],r[4]==="Activo"?"ok":"warn")])),settings:`<article class="card"><span class="eyebrow">Configuración</span><h3>Preferencias iniciales</h3><div class="form-grid">${["Idioma de la interfaz","Zona horaria","Modo de revisión","Publicación automática","Proveedor IA","Cumplimiento"].map(t=>`<div class="field"><label>${t}</label><input readonly value="Preparado para configurar" /></div>`).join("")}</div></article>`,apis:tabla(["Servicio","Uso futuro","Estado"],[["YouTube","Publicación y métricas oficiales",badge("Pendiente","warn")],["Instagram","Reels y métricas oficiales",badge("Pendiente","warn")],["Facebook","Video y páginas",badge("Pendiente","warn")],["TikTok","Publicación oficial",badge("Pendiente","warn")]]),"mission-control":`${metricas()}<div class="grid two">${estado()}${produccion()}</div>`,system:`${estado()}${metricas()}`,company:`<article class="card"><span class="eyebrow">Empresa matriz</span><h3>AppFactoryChile</h3><p>Correo principal: appfactorychile@gmail.com</p><p class="muted">Proyecto oficial: APP FACTORY VIDEO IA.</p></article>`,projects:tabla(["Proyecto","Canal","Estado","Último paso"],[["IA para pymes","Futuro Latino IA",badge("En curso","info"),"Plan de producción"],["Ahorro energético","Brasil Solar",badge("Borrador","warn"),"Ideas"]]),videos:`<div class="video-grid">${["Idea","Guion","Guion gráfico","Plan","Proyecto","Canal","Hook","Informe"].map((t,i)=>`<article class="card video-card"><div class="thumb">${String(i+1).padStart(2,"0")}</div><div class="video-card-body"><h3>${t}</h3><p class="muted">Elemento preparado en modo demostración.</p>${badge("Biblioteca","info")}</div></article>`).join("")}</div>`,agents:tabla(["Agente","Función","Estado"],[["Analista IA","Detecta oportunidades",badge("Activo","ok")],["Guionista IA","Prepara historias",badge("Activo","ok")],["Editor IA","Planifica producción",badge("Planificado","info")]])};return `${ayuda(id)}${contenido[id]||`<article class="card"><h3>${titulo(id)}</h3><p>Sección preparada para siguientes fases.</p></article>`}`}
function postFlujo(ruta,cuerpo){return fetch(`${API_BASE}${ruta}`,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(cuerpo)}).then(r=>{if(!r.ok)throw new Error(UI.error);return r.json()})}
function sync(r){estadoFlujo.workflowId=r.workflow_id||estadoFlujo.workflowId;estadoFlujo.progreso=r.progress||estadoFlujo.progreso;estadoFlujo.estado="listo";estadoFlujo.error=""}
function datosCanal(){const v=id=>document.getElementById(id)?.value.trim()||"";const modo=document.querySelector('input[name="workflowMode"]:checked')?.value||"manual";return{name:v("wfName"),country:v("wfCountry"),language:v("wfLanguage"),niche:v("wfNiche"),description:v("wfDescription"),daily_video_count:Number(v("wfDailyVideos")||8),platforms:v("wfPlatforms").split(",").map(x=>x.trim()).filter(Boolean),mode:modo}}
async function accionFlujo(accion,p={}){try{estadoFlujo.estado="cargando";estadoFlujo.error="";renderScreen("mvp-workflow");let r;if(accion==="create-channel"){r=await postFlujo("/api/workflow/create-channel",datosCanal());sync(r);estadoFlujo.canal=r.channel}if(accion==="analyze-opportunity"){r=await postFlujo("/api/workflow/analyze-opportunity",{workflow_id:estadoFlujo.workflowId});sync(r);estadoFlujo.oportunidad=r;estadoFlujo.decisionEjecutiva=r.executive_decision}if(accion==="generate-ideas"){r=await postFlujo("/api/workflow/generate-ideas",{workflow_id:estadoFlujo.workflowId});sync(r);estadoFlujo.ideas=r.ideas}if(accion==="choose-idea"){r=await postFlujo("/api/workflow/choose-idea",{workflow_id:estadoFlujo.workflowId,idea_id:p.ideaId});sync(r);estadoFlujo.ideaElegida=r.selected_idea}if(accion==="generate-hooks"){r=await postFlujo("/api/workflow/generate-hooks",{workflow_id:estadoFlujo.workflowId});sync(r);estadoFlujo.hooks=r.hooks}if(accion==="choose-hook"){r=await postFlujo("/api/workflow/choose-hook",{workflow_id:estadoFlujo.workflowId,hook_id:p.hookId});sync(r);estadoFlujo.hookElegido=r.selected_hook}if(accion==="generate-story"){r=await postFlujo("/api/workflow/generate-story",{workflow_id:estadoFlujo.workflowId});sync(r);estadoFlujo.historia=r}if(accion==="generate-production-plan"){r=await postFlujo("/api/workflow/generate-production-plan",{workflow_id:estadoFlujo.workflowId});sync(r);estadoFlujo.plan=r}if(accion==="ready-to-generate"){r=await postFlujo("/api/workflow/ready-to-generate",{workflow_id:estadoFlujo.workflowId});sync(r);estadoFlujo.listo=r}renderScreen("mvp-workflow")}catch(e){estadoFlujo.estado="error";estadoFlujo.error=e.message;renderScreen("mvp-workflow")}}
function barra(){const pasos=[["channel","Canal"],["opportunity","Oportunidad"],["ideas","Ideas"],["idea_selected","Idea"],["hooks","Hook"],["storyboard","Guion gráfico"],["production","Producción"],["ready","Listo"]];return `<article class="card workflow-progress"><span class="eyebrow">Flujo guiado</span><h3>Avanza paso a paso</h3><div class="workflow-steps">${pasos.map(([k,l])=>`<span class="${estadoFlujo.progreso[k]?"done":""}">${l} ${estadoFlujo.progreso[k]?"✓":""}</span>`).join("")}</div>${estadoFlujo.error?`<p class="muted workflow-error">${estadoFlujo.error}</p>`:""}</article>`}
function formCanal(){return `<article class="card"><span class="eyebrow">Paso 1</span><h3>Crear canal</h3><div class="form-grid"><div class="field"><label>Nombre</label><input id="wfName" value="Futuro Latino IA" /></div><div class="field"><label>País</label><input id="wfCountry" value="México" /></div><div class="field"><label>Idioma</label><input id="wfLanguage" value="Español" /></div><div class="field"><label>Nicho</label><input id="wfNiche" value="Tecnología" /></div><div class="field"><label>Videos diarios</label><input id="wfDailyVideos" type="number" value="8" /></div><div class="field"><label>Plataformas</label><input id="wfPlatforms" value="YouTube Shorts, Instagram Reels, TikTok" /></div><div class="field workflow-span"><label>Descripción</label><input id="wfDescription" value="Herramientas de IA para pequeñas empresas" /></div><div class="field"><label>Modo</label><div class="mode-toggle"><label><input type="radio" name="workflowMode" value="automatic" /> Automático</label><label><input type="radio" name="workflowMode" value="manual" checked /> Manual</label></div></div></div><button class="primary-btn" data-workflow-action="create-channel">Guardar canal</button></article>`}
function ideasFlujo(){return estadoFlujo.ideas.map((x,i)=>`<article class="workflow-choice ${estadoFlujo.ideaElegida?.id===x.id?"selected":""}"><strong>${["La razón oculta por la que esta herramienta importa ahora","Cómo ahorrar una hora usando IA de forma simple","Lo que muchos entienden mal sobre la IA","Una historia local sobre IA para pequeñas empresas","Antes de ignorar esta tendencia, mira esto","La prueba de 3 segundos para entender la oportunidad","Por qué los creadores hablan de este tema","La forma segura de probar esta idea","El detalle pequeño que cambia todo","Qué viene después en esta tendencia"][i]||"Idea recomendada"}</strong><p>Promesa clara, útil y responsable para el público del canal.</p><div class="style-meta"><span>Curiosidad ${x.curiosity}</span><span>Nivel viral ${x.viral_level}</span><span>Monetización ${x.monetization}</span><span>Retención ${x.retention}</span></div><button class="ghost-btn" data-workflow-action="choose-idea" data-idea-id="${x.id}">Elegir idea</button></article>`).join("")}
function hooksFlujo(){return estadoFlujo.hooks.map((x,i)=>`<div class="hook-card ${estadoFlujo.hookElegido?.id===x.id?"selected":""}"><strong>${datos.hooks[i]?.[0]||"Hook recomendado"}</strong><span>${x.score}/100</span><small>Alta retención esperada</small><button class="ghost-btn" data-workflow-action="choose-hook" data-hook-id="${x.id}">Seleccionar hook</button></div>`).join("")}
function pantallaFlujo(){return `${ayuda("mvp-workflow")}${barra()}${formCanal()}${estadoFlujo.canal?`<article class="card"><span class="eyebrow">Paso 2</span><h3>Auditar oportunidad</h3>${estadoFlujo.oportunidad?`<div class="grid four"><article class="metric-card"><small>Nivel de oportunidad</small><span class="metric-value">${estadoFlujo.oportunidad.opportunity_score}</span></article><article class="metric-card"><small>Competencia</small><span class="metric-value">${estadoFlujo.oportunidad.competition}</span></article><article class="metric-card"><small>Potencial</small><span class="metric-value">${estadoFlujo.oportunidad.potential}</span></article><article class="metric-card"><small>Decisión</small><span class="metric-value">${estadoFlujo.decisionEjecutiva?.decision||"Pendiente"}</span></article></div><div class="ready-card card"><span class="eyebrow">Director Ejecutivo IA</span><h3>${estadoFlujo.decisionEjecutiva?.decision||"Evaluando"}</h3><p>${estadoFlujo.decisionEjecutiva?.rationale||"La IA decide si vale la pena producir antes de gastar recursos."}</p></div>`:`<p class="muted">El Director Ejecutivo IA auditará popularidad, competencia, costo, ROI y riesgo antes de continuar.</p>`}<button class="primary-btn" data-workflow-action="analyze-opportunity">Auditar oportunidad</button></article>`:""}${estadoFlujo.oportunidad?`<article class="card"><span class="eyebrow">Pasos 3 y 4</span><h3>Generar y elegir idea</h3>${estadoFlujo.ideas.length?`<div class="workflow-idea-grid">${ideasFlujo()}</div>`:`<p class="muted">Solo se generan ideas cuando la decisión ejecutiva es PRODUCIR.</p>`}<button class="primary-btn" data-workflow-action="generate-ideas">Generar 10 ideas</button></article>`:""}${estadoFlujo.ideaElegida?`<article class="card"><span class="eyebrow">Paso 5</span><h3>Generar hook</h3>${estadoFlujo.hooks.length?`<div class="hook-stack">${hooksFlujo()}</div>`:`<p class="muted">Genera 5 opciones de inicio para la idea elegida.</p>`}<button class="primary-btn" data-workflow-action="generate-hooks">Generar hooks</button></article>`:""}${estadoFlujo.hookElegido?`<article class="card"><span class="eyebrow">Pasos 6 y 7</span><h3>Estrategia narrativa y storyboard</h3>${estadoFlujo.historia?`${historia()}<div class="scene-grid">${[1,2,3,4].map(n=>`<article class="scene-card"><span>Escena ${n}</span><strong>${["Problema principal","Ejemplo local","Comparación simple","Cierre con llamada a la acción"][n-1]}</strong><p>${["Abrimos con una pregunta clara.","Mostramos la idea con un caso concreto.","Explicamos el beneficio sin exagerar.","Invitamos a conversar de forma responsable."][n-1]}</p><small>Subtítulo breve y claro.</small></article>`).join("")}</div>`:`<p class="muted">Genera objetivo, narrador, personaje, escenario, tono, duración, estilo y storyboard.</p>`}<button class="primary-btn" data-workflow-action="generate-story">Generar estrategia narrativa</button></article>`:""}${estadoFlujo.historia?`<article class="card"><span class="eyebrow">Paso 8</span><h3>Plan de producción</h3>${estadoFlujo.plan?plan():`<p class="muted">Define narrador, voz, formato, música, iluminación, cámara, color y ritmo.</p>`}<button class="primary-btn" data-workflow-action="generate-production-plan">Generar plan de producción</button></article>`:""}${estadoFlujo.plan?`<article class="card ready-card"><span class="eyebrow">Paso 9</span><h3>${estadoFlujo.listo?"Todo está listo para generar el video.":"Listo para generar el video"}</h3><p>No se generará video todavía. El proyecto queda preparado para una fase futura.</p>${estadoFlujo.listo?badge("Listo","ok"):`<button class="primary-btn" data-workflow-action="ready-to-generate">Marcar como listo</button>`}</article>`:""}`}
const pageTitle=document.getElementById("pageTitle"),sideNav=document.getElementById("sideNav"),toast=document.getElementById("toast"),sidebar=document.querySelector(".sidebar"),view=document.getElementById("view");
const gruposAbiertos = new Set(["Inicio"]);
function grupoDePantalla(id){const normal=alias[id]||id||"inicio";const grupo=categorias.find(([_,items])=>items.some(([itemId])=>itemId===normal));return grupo?.[0]||"Inicio"}
function sincronizarMenu(id){const grupoActivo=grupoDePantalla(id);gruposAbiertos.add(grupoActivo);document.querySelectorAll(".nav-group").forEach(g=>{const abierto=gruposAbiertos.has(g.dataset.group);g.classList.toggle("open",abierto);g.querySelector(".nav-toggle")?.setAttribute("aria-expanded",String(abierto));const flecha=g.querySelector(".nav-arrow");if(flecha)flecha.textContent=abierto?"▼":"▶"});document.querySelectorAll(".nav-link").forEach(a=>a.classList.toggle("active",a.dataset.id===(alias[id]||id||"inicio")))}
function renderScreen(id){const normal=alias[id]||id||"inicio";const p=pantallas.find(x=>x.id===normal)||pantallas[0];pageTitle.textContent=p.label;sincronizarMenu(p.id);view.innerHTML=p.id==="inicio"?inicio():p.id==="mvp-workflow"?pantallaFlujo():pantalla(p.id);bindActions()}
function bindActions(){
  document.querySelectorAll("[data-soon]").forEach(b=>b.addEventListener("click",()=>{toast.textContent=UI.pronto;toast.classList.add("show");setTimeout(()=>toast.classList.remove("show"),1500)}));
  document.querySelectorAll("[data-go]").forEach(b=>b.addEventListener("click",()=>location.hash=b.dataset.go));
  document.querySelectorAll("[data-workflow-action]").forEach(b=>b.addEventListener("click",()=>accionFlujo(b.dataset.workflowAction,{ideaId:b.dataset.ideaId,hookId:b.dataset.hookId})));
  document.querySelectorAll("[data-project-action]").forEach(b=>b.addEventListener("click",()=>accionProyecto(b.dataset.projectAction,b.dataset.projectId)));
  document.querySelectorAll("[data-production-action]").forEach(b=>b.addEventListener("click",()=>accionProduccionIA(b.dataset.productionAction,b.dataset.jobId)));
  document.querySelectorAll("[data-ai-action]").forEach(b=>b.addEventListener("click",()=>accionIA(b.dataset.aiAction)));
  document.querySelectorAll("[data-animation-action]").forEach(b=>b.addEventListener("click",()=>accionAnimacion(b.dataset.animationAction)));
  document.querySelectorAll("[data-render-action='test-video']").forEach(b=>b.addEventListener("click",generarPrimerRender));
  document.querySelectorAll("[data-render-action='motion-graphics']").forEach(b=>b.addEventListener("click",aplicarMotionGraphics));
  document.querySelectorAll("[data-image-video-action='create']").forEach(b=>b.addEventListener("click",crearVideoDesdeImagen));
  document.querySelectorAll("[data-narration-action]").forEach(b=>b.addEventListener("click",()=>accionNarracion(b.dataset.narrationAction)));
  document.querySelectorAll("#characterSelect,#characterExpression,#characterPose,#characterAnimation").forEach(el=>el.addEventListener("change",()=>{sincronizarControlesPersonaje();estadoPersonajes.preview=null;route()}));
  document.querySelectorAll("[data-character-action='preview']").forEach(b=>b.addEventListener("click",()=>{sincronizarControlesPersonaje();previsualizarPersonaje()}));
  document.getElementById("imageVideoFile")?.addEventListener("change",e=>subirImagenVideo(e.target.files?.[0]));
  const dz=document.getElementById("projectDropzone");
  if(dz){dz.addEventListener("click",()=>accionProyecto("fake-docs"));dz.addEventListener("dragover",e=>{e.preventDefault();dz.classList.add("dragging")});dz.addEventListener("dragleave",()=>dz.classList.remove("dragging"));dz.addEventListener("drop",e=>{e.preventDefault();dz.classList.remove("dragging");accionProyecto("fake-docs")})}
}
function bindNav(){document.querySelectorAll(".nav-toggle").forEach(b=>b.addEventListener("click",()=>{const grupo=b.closest(".nav-group")?.dataset.group;if(!grupo)return;gruposAbiertos.has(grupo)?gruposAbiertos.delete(grupo):gruposAbiertos.add(grupo);sincronizarMenu(location.hash.replace("#","")||"inicio")}))}
function buildNav(){sideNav.innerHTML=categorias.map(([nombre,items])=>`<div class="nav-group" data-group="${nombre}"><button class="nav-toggle" type="button" aria-expanded="${gruposAbiertos.has(nombre)}"><span class="nav-arrow">${gruposAbiertos.has(nombre)?"▼":"▶"}</span><span>${nombre}</span><small>${items.length}</small></button><div class="nav-items">${items.map(([id,label,icon,kpi])=>`<a class="nav-link" href="#${id}" data-id="${id}" title="${label}"><span class="nav-icon">${icon}</span><span>${label}</span><small class="nav-kpi">${kpi}</small></a>`).join("")}</div></div>`).join("");bindNav()}
function route(){renderScreen(location.hash.replace("#","")||"inicio");sidebar.classList.remove("open")}
document.getElementById("menuToggle").addEventListener("click",()=>sidebar.classList.toggle("open"));window.addEventListener("hashchange",route);buildNav();route();












